// Stage 1: PubMed 논문 수집
const searchTerms = [
  'sleep duration dementia risk longitudinal',
  'glymphatic system sleep brain clearance',
  'dementia prevention modifiable risk factors 2024',
  'cognitive decline exercise BDNF elderly',
  'mediterranean diet cognitive aging brain',
];

const results = [];

for (const term of searchTerms) {
  await new Promise(r => setTimeout(r, 400));

  const searchUrl = `https://eutils.ncbi.nlm.nih.gov/entrez/eutils/esearch.fcgi?db=pubmed&term=${encodeURIComponent(term)}&retmax=3&sort=relevance&retmode=json&datetype=pdat&reldate=730`;

  const searchRes = await fetch(searchUrl);
  const searchData = await searchRes.json();
  const pmids = searchData.esearchresult?.idlist || [];

  if (pmids.length === 0) continue;

  await new Promise(r => setTimeout(r, 400));
  const fetchUrl = `https://eutils.ncbi.nlm.nih.gov/entrez/eutils/efetch.fcgi?db=pubmed&id=${pmids.join(',')}&retmode=xml&rettype=abstract`;
  const fetchRes = await fetch(fetchUrl);
  const xml = await fetchRes.text();

  // 간단 XML 파싱
  const titles = xml.match(/<ArticleTitle>(.*?)<\/ArticleTitle>/gs) || [];
  const pmidMatches = xml.match(/<PMID[^>]*>(\d+)<\/PMID>/g) || [];

  for (let i = 0; i < Math.min(titles.length, pmidMatches.length); i++) {
    const title = titles[i].replace(/<[^>]+>/g, '').trim();
    const pmid = pmidMatches[i].replace(/<[^>]+>/g, '').trim();
    results.push({ title, pmid, searchTerm: term, url: `https://pubmed.ncbi.nlm.nih.gov/${pmid}/` });
  }
}

return [{ json: { articles: results, fetchedAt: new Date().toISOString(), count: results.length } }];

