// Claude 응답 파싱 + 팩트체크 준비
const raw = $input.first().json.content[0].text;
const cleaned = raw.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();

let script;
try {
  script = JSON.parse(cleaned);
} catch(e) {
  throw new Error('Claude 응답 JSON 파싱 실패: ' + e.message);
}

// 자동 위험 표현 스캔
const redFlagPatterns = [
  { pattern: /반드시|절대|무조건|100%/, reason: '단정적 표현' },
  { pattern: /기적|혁명적/, reason: '과장 표현' },
  { pattern: /확실히 예방|완전 치료/, reason: '의학적 과장' },
];

const redFlags = redFlagPatterns.filter(r => r.pattern.test(JSON.stringify(script)));

return [{ json: { 
  script, 
  redFlags, 
  hasRedFlags: redFlags.length > 0,
  generatedAt: new Date().toISOString()
} }];

